--

CREATE FUNCTION public.update_learning_progress() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    VALUES (NEW.user_id, CURRENT_DATE, 1, NEW.score_percentage)
    ON CONFLICT (user_id, progress_date) 
    DO UPDATE SET 
        quizzes_attempted = learning_progress.quizzes_attempted + 1,
        average_quiz_score = (learning_progress.average_quiz_score * learning_progress.quizzes_attempted + NEW.score_percentage) / (learning_progress.quizzes_attempted + 1);
    RETURN NEW;
END;
$$;


